/* simple.h — all scalar C numeric types */
#ifndef SIMPLE_H
#define SIMPLE_H

typedef struct SimpleScalars {
    char              a_char;
    unsigned char     a_uchar;
    short             a_short;
    unsigned short    a_ushort;
    int               a_int;
    unsigned int      a_uint;
    long              a_long;
    unsigned long     a_ulong;
    long long         a_longlong;
    unsigned long long a_ulonglong;
    float             a_float;
    double            a_double;
} SimpleScalars;

#endif /* SIMPLE_H */
